from fastapi import FastAPI, Depends, HTTPException
from sqlalchemy import create_engine, Column, Integer, String, Boolean
from sqlalchemy.orm import sessionmaker, DeclarativeBase, Session
from pydantic import BaseModel, Field

# Database
engine = create_engine('sqlite:///./todos.db', connect_args={'check_same_thread': False})
SessionLocal = sessionmaker(bind=engine)

class Base(DeclarativeBase): pass

class Todo(Base):
    __tablename__ = 'todos'
    id = Column(Integer, primary_key=True, index=True)
    title = Column(String(200), nullable=False)
    description = Column(String(500), default='')
    is_done = Column(Boolean, default=False)
    priority = Column(Integer, default=1)

Base.metadata.create_all(bind=engine)

class TodoCreate(BaseModel):
    title: str = Field(..., min_length=1)
    description: str = ''
    priority: int = Field(default=1, ge=1, le=5)

class TodoResponse(TodoCreate):
    id: int
    is_done: bool
    class Config:
        from_attributes = True

app = FastAPI()

def get_db():
    db = SessionLocal()
    try: yield db
    finally: db.close()

@app.post('/todos/', response_model=TodoResponse, status_code=201)
def create_todo(todo: TodoCreate, db: Session = Depends(get_db)):
    db_todo = Todo(**todo.model_dump())
    db.add(db_todo); db.commit(); db.refresh(db_todo)
    return db_todo

@app.get('/todos/', response_model=list[TodoResponse])
def list_todos(db: Session = Depends(get_db)):
    return db.query(Todo).all()

@app.get('/todos/pending', response_model=list[TodoResponse])
def pending_todos(db: Session = Depends(get_db)):
    return db.query(Todo).filter(Todo.is_done == False).order_by(Todo.priority).all()
